const results = $input.first().json.results || [];

const courses = results.map(page => {
  try {
    const props = page.properties;
    const name = props['Course']?.title?.[0]?.plain_text ?? 'Untitled';
    const status = props['Status']?.status?.name ?? 'Not started';
    const platform = props['Platform']?.multi_select?.[0]?.name ?? '—';
    const section = props['Section']?.multi_select?.[0]?.name ?? '—';
    const end_date = props['End Date']?.date?.start ?? '—';
    const start_date = props['Start Date']?.date?.start ?? '—';
    const est_time = props['Est. Time']?.formula?.string ?? '—';
    const time_left = props['TimeLine']?.formula?.string ?? '—';

    // Calculate progress from Est. Time and Time Left
    const est_hours = parseFloat(est_time) || 0;
    const left_hours = parseFloat(time_left) || 0;
    const progress = est_hours > 0
      ? Math.round(((est_hours - left_hours) / est_hours) * 100)
      : (props['Progress']?.number ?? (status === 'Done' ? 100 : 0));

    return { name, status, provider: platform, section, end_date, start_date, est_time, time_left, progress };
  } catch(e) {
    return { name: 'Error', status: 'Not started', provider: '—', section: '—', end_date: '—', start_date: '—', est_time: '—', time_left: '—', progress: 0 };
  }
});

const current = courses.find(c => c.status === 'In progress') ?? null;
const next = courses.find(c => c.status === 'Not started') ?? null;
const overall_progress = courses.length
  ? Math.round(courses.reduce((s, c) => s + c.progress, 0) / courses.length)
  : 0;

return [{ json: { current_course: current, next_course: next, overall_progress, courses } }];
